function solve(nums: number[], k: number): number {
    let modCounts: { [key: number]: number } = {};
    let prefixMod = 0;
    modCounts[0] = 1;

    for (let num of nums) {
        prefixMod = (prefixMod + num) % k;
        modCounts[prefixMod] = (modCounts[prefixMod] || 0) + 1;
    }

    let minSum = 0;
    for (let mod in modCounts) {
        let count = modCounts[mod];
        if (count > 0) {
            minSum += (parseInt(mod) * count);
        }
    }

    return minSum;
}
